// tlVolumeImageChunk

int tlVolumeImageChunk::sortPriority = -1;

tlVolumeImageChunk::tlVolumeImageChunk()
{
    Init();
}

tlVolumeImageChunk::tlVolumeImageChunk(const tlVolumeImageChunk& ch)
{
    Init();
    *this = ch;
}

tlVolumeImageChunk::~tlVolumeImageChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlVolumeImageChunk::tlVolumeImageChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Texture::VOLUME_IMAGE);
    ident = Pure3D::Texture::VOLUME_IMAGE;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    width = f->GetLong();
    height = f->GetLong();
    depth = f->GetLong();
    bpp = f->GetLong();
    palettized = f->GetLong();
    hasalpha = f->GetLong();
    format = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Texture::VOLUME_IMAGE);
    }
}

void
tlVolumeImageChunk::Init()
{
    ident = Pure3D::Texture::VOLUME_IMAGE;
    name = NULL;
    version = 0;
    width = 0;
    height = 0;
    depth = 0;
    bpp = 0;
    palettized = 0;
    hasalpha = 0;
    format = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Texture::VOLUME_IMAGE);
    }
}

long 
tlVolumeImageChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += sizeof( width );
    s += sizeof( height );
    s += sizeof( depth );
    s += sizeof( bpp );
    s += sizeof( palettized );
    s += sizeof( hasalpha );
    s += sizeof( format );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlVolumeImageChunk&
tlVolumeImageChunk::operator=(const tlVolumeImageChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    version = a.version;
    width = a.width;
    height = a.height;
    depth = a.depth;
    bpp = a.bpp;
    palettized = a.palettized;
    hasalpha = a.hasalpha;
    format = a.format;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlVolumeImageChunk::operator==(const tlDataChunk& a)
{

    const tlVolumeImageChunk* aptr = dynamic_cast<const tlVolumeImageChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(width == aptr->width))
    {
        return false;
    }
    if(!(height == aptr->height))
    {
        return false;
    }
    if(!(depth == aptr->depth))
    {
        return false;
    }
    if(!(bpp == aptr->bpp))
    {
        return false;
    }
    if(!(palettized == aptr->palettized))
    {
        return false;
    }
    if(!(hasalpha == aptr->hasalpha))
    {
        return false;
    }
    if(!(format == aptr->format))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlVolumeImageChunk::NameCompare(const tlDataChunk& a)
{

    const tlVolumeImageChunk* aptr = dynamic_cast<const tlVolumeImageChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlVolumeImageChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlVolumeImageChunk(ch);
    return dtCh;
}

void
tlVolumeImageChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutLong(version);
        f->PutLong(width);
        f->PutLong(height);
        f->PutLong(depth);
        f->PutLong(bpp);
        f->PutLong(palettized);
        f->PutLong(hasalpha);
        f->PutLong(format);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlVolumeImageChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlVolumeImageChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name       = \"%s\"\n",indent,"",name);
    printf("%*s  Version    = %ld\n",indent,"",version);
    printf("%*s  Width      = %ld\n",indent,"",width);
    printf("%*s  Height     = %ld\n",indent,"",height);
    printf("%*s  Depth      = %ld\n",indent,"",depth);
    printf("%*s  Bpp        = %ld\n",indent,"",bpp);
    printf("%*s  Palettized = %ld\n",indent,"",palettized);
    printf("%*s  HasAlpha   = %ld\n",indent,"",hasalpha);
    printf("%*s  Format     = %ld\n",indent,"",format);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlVolumeImageChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name      \n",indent,"",name);
    printf("%*s  int   %12ld # Version   \n",indent,"",version);
    printf("%*s  int   %12ld # Width     \n",indent,"",width);
    printf("%*s  int   %12ld # Height    \n",indent,"",height);
    printf("%*s  int   %12ld # Depth     \n",indent,"",depth);
    printf("%*s  int   %12ld # Bpp       \n",indent,"",bpp);
    printf("%*s  int   %12ld # Palettized\n",indent,"",palettized);
    printf("%*s  int   %12ld # HasAlpha  \n",indent,"",hasalpha);
    printf("%*s  int   %12ld # Format    \n",indent,"",format);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

